{
  "module": "02-navigation.md",
  "group": "02 — Navigation & Routing",
  "apiCount": 6,
  "apis": [
    {
      "name": "router (ohos.router)",
      "purpose": "Page routing via URL-based navigation between @Entry pages (deprecated in API 18)",
      "anchor": "router-ohosrouter---deprecated",
      "status": "found"
    },
    {
      "name": "NavPathStack / Navigation",
      "purpose": "Recommended navigation framework container with stack-based routing controller",
      "anchor": "navpathstack--navigation",
      "status": "found"
    },
    {
      "name": "PageTransition",
      "purpose": "Custom page enter/exit transition animation for router-based page switching",
      "anchor": "pagetransition",
      "status": "found"
    },
    {
      "name": "aboutToAppear / aboutToDisappear",
      "purpose": "Universal custom component lifecycle callbacks for initialization and cleanup",
      "anchor": "abouttoappear--abouttodisappear",
      "status": "found"
    },
    {
      "name": "onPageShow / onPageHide / onBackPress",
      "purpose": "Router @Entry page lifecycle callbacks for visibility and back button handling",
      "anchor": "onpageshow--onpagehide--onbackpress",
      "status": "found"
    },
    {
      "name": "NavDestination lifecycle (onShown, onHidden, onWillAppear, onWillShow, onWillHide, onWillDisappear, onReady, onBackPressed)",
      "purpose": "Navigation-based page lifecycle callbacks, replacing @Entry page lifecycle when using Navigation/NavPathStack",
      "anchor": "navdestination-生命周期-navigation-路由使用的替代-lifecycle",
      "status": "found"
    }
  ],
  "notableFindings": [
    "router (ohos.router) is deprecated since API 18 — all new development must use Navigation component with NavPathStack",
    "NavPathStack does NOT require @State/@Provide decoration — it works as a plain member variable",
    "Navigation-based apps use NavDestination lifecycle (onWillAppear/onReady/onShown/onHidden/onWillDisappear/onBackPressed) instead of @Entry lifecycle (onPageShow/onPageHide/onBackPress)",
    "PageTransition works with router-based transitions; Navigation uses its own transition system via NavPathStack animated parameter",
    "NavDestination.onReady provides NavDestinationContext with access to the parent NavPathStack and NavPathInfo"
  ],
  "missingApis": []
}

{
  "module": "03-state.md",
  "group": "03 — State Management",
  "apiCount": 8,
  "apis": [
    {
      "name": "@Watch",
      "purpose": "状态管理V1中监听状态变量变化，变量改变时触发回调函数",
      "anchor": "watch",
      "status": "found"
    },
