    {
      "name": "AppStorage",
      "purpose": "应用全局UI状态存储，支持读写、双向/单向绑定、持久化配合",
      "anchor": "appstorage",
      "status": "found"
    },
    {
      "name": "LocalStorage",
      "purpose": "页面级UI状态存储，支持构造函数初始化、读写、双向/单向绑定",
      "anchor": "localstorage",
      "status": "found"
    },
    {
      "name": "Environment (ohos.environment)",
      "purpose": "设备环境查询，将系统内置环境变量存入AppStorage",
      "anchor": "environment-ohosenvironment",
      "status": "found"
    },
    {
      "name": "@ohos.arkui.StateManagement",
      "purpose": "状态管理V2的AppStorageV2、PersistenceV2、UIUtils等API",
      "anchor": "ohosarkuistatemanagement",
      "status": "found"
    },
    {
      "name": "ProvideOptions (@Provide参数)",
      "purpose": "@Provide装饰器的allowOverride参数选项配置",
      "anchor": "provide--consume",
      "status": "found"
    },
    {
      "name": "内置环境变量 (ColorMode / LayoutDirection)",
      "purpose": "系统内置环境变量的枚举值，用于深浅色模式、布局方向等",
      "anchor": "内置环境变量说明",
      "status": "found"
    }
  ],
  "notableFindings": [
    "@State、@Prop/@Link、@Provide/@Consume、@Observed/@ObjectLink、@StorageProp/@StorageLink 是ArkUI框架内置装饰器，其完整用法在开发者指南文档中，当前API参考目录中无对应独立API文档",
    "@Watch仅支持状态管理V1；V2中对应@Monitor和@SyncMonitor，在03_状态变量变化监听.md中有定义",
    "@ohos.arkui.StateManagement 模块（状态管理V2）通过 import { AppStorageV2, PersistenceV2, UIUtils } from '@kit.ArkUI' 导入",
    "ProvideOptions参数定义在02_状态管理V1装饰器参数.md中，仅用于@Provide的allowOverride配置",
    "Environment类（ohos.environment）用于将系统环境变量存入AppStorage，与@Env装饰器不同"
  ],
  "missingApis": [
    "@State",
    "@Prop / @Link",
    "@Provide / @Consume (装饰器本身)",
    "@Observed / @ObjectLink",
    "@StorageProp / @StorageLink"
  ]
}

